<?php namespace App\Repositories\Academic;use App\Repositories\BaseRepository;use App\Models\Academic\Assignment;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class AssignmentRepository extends BaseRepository{    public function __construct(Assignment $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findBySubject(int $subjectId): Collection    {        return $this->findByField('subject_id', $subjectId);    }    public function findByTeacher(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getUpcomingDeadlines(int $days = 7): Collection    {        return $this->query()->where('due_date', '>=', now())->where('due_date', '<=', now()->addDays($days))->orderBy('due_date', 'asc')->get();    }    public function getOverdueAssignments(): Collection    {        return $this->query()->where('due_date', '<', now())->where('status', 'active')->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('created_at', [$startDate, $endDate])->get();    }    public function searchAssignments(string $keyword): Collection    {        return $this->query()->where('title', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getByClassAndSubject(int $classId, int $subjectId): Collection    {        return $this->query()->where('class_id', $classId)->where('subject_id', $subjectId)->orderBy('created_at', 'desc')->get();    }    public function closeAssignment(int $id): bool    {        return $this->update($id, ['status' => 'closed']);    }}